# Deobfuscated Code

After decoding all the base64 string table entries and resolving all references, here is the clean, deobfuscated code:

```javascript
// Constants
var TAU = 6.283;          // ≈ 2π
var PHI = 1.618;          // Golden ratio
var SQRT1_2 = 0.707;      // ≈ √(1/2)

// Simulation parameters
var config = {
  attractionRange: 4000,       // attraction radius
  springBaseCoeff: 0.004,      // spring base coefficient
  amplification: 0.92,         // velocity damping factor
  gravityPull: 0.0003,         // centering gravity strength
  streamCount: 40,             // max particle count
  streamDecay: 0.04,           // particle drag/decay
  theta: 0.06                  // camera smoothing factor
};

// --- NODES ---
var hub = {
  id: 'hub',
  label: 'Hub',
  r: 26,
  x: 400, y: 300,
  vx: 0, vy: 0
};

var alpha = {
  id: 'alpha',
  label: 'Alpha',
  r: 16,
  x: 500, y: 200,
  vx: 0, vy: 0
};

var beta = {
  id: 'beta',
  label: 'Beta',
  r: 16,
  x: 300, y: 400,
  vx: 0, vy: 0
};

var gamma = {
  id: 'gamma',
  label: 'Gamma',
  r: 14,
  x: 250, y: 180,
  vx: 0, vy: 0
};

var delta = {
  id: 'delta',
  label: 'Delta',
  r: 14,
  x: 550, y: 380,
  vx: 0, vy: 0
};

var epsilon = {
  id: 'epsilon',
  label: 'Epsilon',
  r: 12,
  x: 350, y: 150,
  vx: 0, vy: 0
};

var nodes = [hub, alpha, beta, gamma, delta, epsilon];

// --- EDGES (springs) ---
var edges = [
  { a: 'hub', b: 'alpha',   rest: 160, k: 0.006 },
  { a: 'hub', b: 'beta',    rest: 160, k: 0.005 },
  { a: 'hub', b: 'gamma',   rest: 170, k: 0.004 },
  { a: 'hub', b: 'delta',   rest: 170, k: 0.004 },
  { a: 'hub', b: 'epsilon', rest: 180, k: 0.003 },
  { a: 'alpha', b: 'beta',    rest: 200, k: 0.002 },
  { a: 'gamma', b: 'delta',   rest: 220, k: 0.002 },
  { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

// --- CAMERA ---
var camera = { x: 400, y: 300, zoom: 1 };
var cameraTarget = { x: 400, y: 300, zoom: 1 };

// --- PARTICLES ---
var particles = [];
var tickCount = 0;

// --- HELPER: find node by id ---
function findNode(id) {
  for (var i = 0; i < nodes.length; i++) {
    if (nodes[i].id === id) return nodes[i];
  }
  return null;
}

// --- PHYSICS: apply forces ---
function applyForces() {
  // 1. Node-node repulsion (Coulomb-like)
  for (var i = 0; i < nodes.length; i++) {
    for (var j = i + 1; j < nodes.length; j++) {
      var dx = nodes[i].x - nodes[j].x;
      var dy = nodes[i].y - nodes[j].y;
      var dist = Math.sqrt(dx * dx + dy * dy) || 1;
      var force = config.attractionRange / (dist * dist);
      var fx = (dx / dist) * force;
      var fy = (dy / dist) * force;
      nodes[i].vx += fx;
      nodes[i].vy += fy;
      nodes[j].vx -= fx;
      nodes[j].vy -= fy;
    }
  }

  // 2. Spring forces along edges (Hooke's law)
  for (var e = 0; e < edges.length; e++) {
    var nodeA = findNode(edges[e].a);
    var nodeB = findNode(edges[e].b);
    if (!nodeA || !nodeB) continue;
    var dx = nodeB.x - nodeA.x;
    var dy = nodeB.y - nodeA.y;
    var dist = Math.sqrt(dx * dx + dy * dy) || 1;
    var displacement = dist - edges[e].rest;
    var force = (edges[e].k || config.springBaseCoeff) * displacement;
    nodeA.vx += (dx / dist) * force;
    nodeA.vy += (dy / dist) * force;
    nodeB.vx -= (dx / dist) * force;
    nodeB.vy -= (dy / dist) * force;
  }

  // 3. Centering gravity + velocity damping + position integration
  for (var n = 0; n < nodes.length; n++) {
    // Centering gravity toward (400, 300)
    nodes[n].vx += (400 - nodes[n].x) * config.gravityPull;
    nodes[n].vy += (300 - nodes[n].y) * config.gravityPull;
    // Damping
    nodes[n].vx *= config.amplification;
    nodes[n].vy *= config.amplification;
    // Integration
    nodes[n].x += nodes[n].vx;
    nodes[n].y += nodes[n].vy;
  }
}

// --- PARTICLE SPAWNER ---
function spawnParticle() {
  if (particles.length >= config.streamCount) return;
  var source = nodes[Math.floor(Math.random() * nodes.length)];
  var angle = Math.random() * TAU;
  var speed = 0.3 + Math.random() * SQRT1_2;
  particles.push({
    x: source.x,
    y: source.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + (Math.random() * PHI) * SQRT1_2
  });
}

// --- PARTICLE UPDATER ---
function updateParticles() {
  for (var i = particles.length - 1; i >= 0; i--) {
    var p = particles[i];
    // Age and remove expired
    p.age++;
    if (p.age > p.maxAge) {
      particles.splice(i, 1);
      continue;
    }
    // Apply drag
    p.vx *= (1 - config.streamDecay * 0.125);
    p.vy *= (1 - config.streamDecay * 0.125);
    // Move
    p.x += p.vx;
    p.y += p.vy;
  }
}

// --- CAMERA SMOOTHER ---
function updateCamera() {
  camera.x += (cameraTarget.x - camera.x) * config.theta;
  camera.y += (cameraTarget.y - camera.y) * config.theta;
  camera.zoom += (cameraTarget.zoom - camera.zoom) * config.theta;
}

// --- MAIN TICK ---
function tick() {
  applyForces();
  updateParticles();
  updateCamera();
  if (tickCount % 3 === 0) spawnParticle();
  tickCount++;
}

setInterval(tick, 16); // ~60 FPS
```

## Summary

This is a **force-directed graph layout simulation** with:

| Component | Algorithm |
|---|---|
| **Repulsion** | Coulomb's law — nodes repel each other inversely proportional to distance² |
| **Springs** | Hooke's law — edges pull connected nodes toward a rest length |
| **Centering** | Gentle gravity pulling all nodes toward (400, 300) |
| **Damping** | Velocity multiplied by 0.92 each tick (energy dissipation) |
| **Particles** | Cosmetic stream particles spawned from random nodes, fading over time |
| **Camera** | Exponential smoothing (lerp) toward a target position/zoom |

The graph has a **hub-and-spoke topology**: a central "Hub" node connected to 5 satellites (Alpha, Beta, Gamma, Delta, Epsilon), with a few cross-links (Alpha↔Beta, Gamma↔Delta, Alpha↔Epsilon).
